// // This module outputs a low signal when a toggle input is active and the `cyc` input equals 5, while also printing a message to the console when this condition is met. The output is set to high on any other condition, making this module suitable for monitoring specific cycles in a clock-driven system as a form of event detection.
module top_module(
   input clk,
   input toggle,
   input [31:0] cyc,
   output reg out
   );always @(posedge clk) begin
      if (toggle && cyc == 5) begin
         out <= 1;
         $display("*COVER: Cyc==5");
      end
      else begin
         out <= 0;
      end
   end

endmodule
